#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int maxProd, currMax, currMin, num;
        if (n == 0) { printf("0\n"); continue; }
        scanf("%d", &num);
        maxProd = currMax = currMin = num;
        for (int i = 1; i < n; ++i) {
            scanf("%d", &num);
            if (num < 0) {
                int tmp = currMax; currMax = currMin; currMin = tmp;
            }
            if (currMax * num > num) currMax = currMax * num; else currMax = num;
            if (currMin * num < num) currMin = currMin * num; else currMin = num;
            if (currMax > maxProd) maxProd = currMax;
        }
        printf("%d\n", maxProd);
    }
    return 0;
}

